import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/81-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/81-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/81-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 帝驾临博尔扎诺到现在发生的事情。陛下于上月6日前后到达此处，人们 原本以为他的到来会推动事态的进展，结果却适得其反。人们看到：他一 开始是为自己的事情而召开会议，后来又到处请求别人给予资金援助，而 且他在特伦特只有少量军队。 一方面，皇帝已经走得太远， 一旦回头将十 分丢脸；另一方面，他没有足够的军队去采取进一步行动，所有人的热情 也开始冷却下来。因此，正如我在17日的信中所言，我认为还有时间可以 等待诸位大人的回复。但是，我也补充说明，因为这个地区十分广阔，再 加上皇帝向来行事机密，意外的事情随时可能发生。此后，我们看到从上 月20日到今天，事情又有新的进展。新征集的步兵不断到达这里，大批 炮兵被送往他处，每天还有大量的骑兵来到此地。虽然根据我们的观察， 途经这里的步兵数量不超过3000人，骑兵只有1000人。但是，据我目前 所知，无论是这里，还是特伦特或周边地区，目前军队的数量与我之前给 诸位大人写信时相比，并无增多。不过，人们确信，就像我们在这里看到 的那样，还有一群步兵和相应比例的骑兵，正从别的路线经过。所以，即 便是最多疑的人，也不再怀疑备战的工作正在进行中。这也是为什么,从 上月24日到本月1日，我在所有的信件中都写到战事正在推进。除非皇帝 想让自己蒙羞，或者想要缔结什么体面的协议，否则他很可能会前往意大 利。〉随后，皇帝离开博尔扎诺，在这里和特伦特之间的不同地区经过， 并于周四的23点左右进入那个城镇。接下来那天，皇帝亲自加入了一支威 严的队伍。因为皇帝比他的御用先锋提前到达，所以他手中拿着出鞘的利 刃，亲自前往教堂。在那里，朗向民众宣布皇帝准备向意大利采取的行动 云云。周五全天，士兵在城门把守，允许人们进城，但不准任何人出城。 城里所有善于使用斧头的人，都被雇去砍柴，准备制作木栅和木筐。当地 政府还下令制作面包，数量之大足以为10000人提供4天口粮。 一批满载各 种军用品的木筏，正沿着阿迪杰河行驶。那天夜里，所有重骑兵都接到命 令，要随时做好准备，在听到第一声号角时马上动身。大约9点时，他们 全体出动，而且安静得让人肃然起敬。",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolò Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
